
@import '../styles/global.scss';

.main-interface {
  position: relative;
  width: 100%;
  aspect-ratio: 16 / 9; // 使用 aspect-ratio 控制高度，不使用 vh
  overflow: hidden;
}

// ==================== 层级结构 ====================
.layer {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none; // 默认不接收事件

  // 子元素可以接收事件
  > * {
    pointer-events: auto;
  }
}

.layer-background {
  z-index: $z-index-background;
}

.layer-sprite {
  z-index: $z-index-sprite;
}

.layer-ui {
  z-index: $z-index-ui;
}

.control-panel {
  @include control-panel-position;

  // 添加底部渐变遮罩，提示可以滚动
  &::after {
    content: '';
    position: sticky;
    bottom: 0;
    left: 0;
    right: 0;
    height: 20px;
    background: linear-gradient(to top, rgba(0, 0, 0, 0.5), transparent);
    pointer-events: none;
    opacity: 0;
    transition: opacity $transition-base;
  }

  // 当内容超出时显示渐变
  &:hover::after {
    opacity: 1;
  }

  @include mobile {
    // 移动端始终显示渐变提示
    &::after {
      opacity: 0.7;
    }
  }
}

.control-btn {
  @include control-button;
  flex-shrink: 0; // 防止按钮被压缩
}

.modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(0, 0, 0, 0.8);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: $z-index-modal;
  backdrop-filter: blur(4px);
}

.ui-toggle-btn {
  @include round-button;
  @include fixed-bottom-left;

  // UI 隐藏时半透明
  &.ui-hidden {
    opacity: 0.5;
    background: rgba(20, 20, 20, 0.6);

    &:hover {
      opacity: 0.8;
    }
  }
}

.toggle-dialogue-btn {
  @include round-button;
  @include fixed-bottom-right;

  &.active {
    background: rgba(212, 175, 55, 0.3);
    border-color: $color-secondary-gold;
    box-shadow: $shadow-gold;
  }
}

.fullscreen-btn {
  @include round-button;
  @include fixed-top-right;
}

.plot-review-btn {
  @include round-button;
  @include fixed-top-left;

  &.active {
    background: rgba(212, 175, 55, 0.3);
    border-color: $color-secondary-gold;
    box-shadow: $shadow-gold;
  }
}
